const overlay=document.getElementById('modal-overlay');const formView=document.getElementById('modal-form-view');const successView=document.getElementById('modal-success');const form=document.getElementById('contact-form');const submitBtn=document.getElementById('submit-btn');const emailInput=document.getElementById('cf-email');const emailError=document.getElementById('email-error');function openModal(){overlay.classList.add('open');document.body.style.overflow='hidden';setTimeout(()=>{document.getElementById('cf-name').focus();},320);}
function closeModal(){overlay.classList.remove('open');document.body.style.overflow='';emailInput.classList.remove('input-invalid');emailError.classList.remove('show');}
function resetModal(){form.reset();formView.style.display='';successView.classList.remove('show');submitBtn.disabled=false;submitBtn.textContent='wyślij wiadomość';}
document.getElementById('fab').addEventListener('click',()=>{resetModal();openModal();});document.getElementById('modal-close').addEventListener('click',closeModal);document.getElementById('modal-close-success').addEventListener('click',closeModal);overlay.addEventListener('click',(e)=>{if(e.target===overlay)closeModal();});document.addEventListener('keydown',(e)=>{if(e.key==='Escape'&&overlay.classList.contains('open'))closeModal();});form.addEventListener('submit',(e)=>{e.preventDefault();const name=document.getElementById('cf-name').value.trim();const email=document.getElementById('cf-email').value.trim();const message=document.getElementById('cf-message').value.trim();const emailRegex=/^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/;emailInput.classList.remove('input-invalid');emailError.classList.remove('show');if(!name||!email||!message)return;if(!emailRegex.test(email)){emailInput.classList.add('input-invalid');emailError.classList.add('show');emailInput.focus();return;}
submitBtn.disabled=true;submitBtn.textContent='wysyłanie...';const SCRIPT_URL='https://script.google.com/macros/s/AKfycbw2fICiq0PSQ-2aWIhq6Gaj6LsImryDQRnelBnPzOoG8aU_1MRN29kXWl-Pg0m3q4ICPA/exec';const formData=new FormData();formData.append('name',name);formData.append('email',email);formData.append('subject',document.getElementById('cf-subject').value.trim());formData.append('message',message);fetch(SCRIPT_URL,{method:'POST',body:formData}).then(r=>r.json()).then(data=>{if(data.result==='success'){formView.style.display='none';successView.classList.add('show');}else{submitBtn.disabled=false;submitBtn.textContent='wyślij wiadomość';alert('Coś poszło nie tak. Napisz bezpośrednio na mail@alanmyszka.pl');}}).catch(()=>{submitBtn.disabled=false;submitBtn.textContent='wyślij wiadomość';alert('Błąd połączenia. Napisz bezpośrednio na mail@alanmyszka.pl');});});